        domain_part, _ = netloc.split(':', 1)
    else:
        domain_part = netloc
    if domain_part in ALLOWED_REDIRECT_DOMAINS:
        return parsed_url.geturl()
    else:
        raise ValueError("Redirect to unauthorized domain")

def resolve_image_url(image_url: str) -> str | None:
    parsed_url = urlparse(image_url)
    if parsed_url.scheme not in ALLOWED_SCHEMES:
        return None
    netloc = parsed_url.netloc
    if ':' in netloc:
        domain = netloc.split(':', 1)[0]
    else:
        domain = netloc
    if domain in TRUSTED_IMAGE_HOSTS:
        return image_url
    return None

import math

def process_user_expression(expr: str) -> str:
    try:
        allowed_globals = {
            'math': math,
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'sqrt': math.sqrt,
            'pi': math.pi,
            'e': math.e,
        }
        result = eval(expr, allowed_globals, {})
        return str(result)
    except Exception as e:
        return f"Error: {str(e)}"
